import { useMemo, useState } from "react";
import { Activity } from "lucide-react";
import {
  HubDirectoryBulkActionBar,
  HubDirectoryScreen,
  MiniBarChart,
  useHubDirectorySelection,
  type FilterDef,
  type FilterValues,
  type HubSortDir,
  type KpiTileData,
} from "@tool-workspace/hub-ui";
import { GoldenDirectoryTable } from "./GoldenDirectoryTable";

// TODO: import AppTabHeader or ConsoleTabHeader from your app
// TODO: import configureFilterIcons registry + enrichFilterDefs wrapper

type DemoRow = { id: string; label: string };

const DEMO_ROWS: DemoRow[] = [];

export function GoldenDirectoryScreen() {
  const [query, setQuery] = useState("");
  const [filterValues, setFilterValues] = useState<FilterValues>({});
  const [sortKey, setSortKey] = useState<"label" | "id">("label");
  const [sortDir, setSortDir] = useState<HubSortDir>("asc");
  const filters = useMemo<FilterDef[]>(() => [], []);

  const filtered = useMemo(() => DEMO_ROWS, []);

  const {
    selectedIds,
    allVisibleSelected,
    toggleSelect,
    toggleSelectAll,
  } = useHubDirectorySelection(filtered, (row) => row.id);

  const kpis = useMemo<KpiTileData[]>(
    () => [{ label: "Total", value: 0, icon: Activity, tone: "indigo", prefKey: "total" }],
    [],
  );

  const charts = (
    <>
      <MiniBarChart title="By category" items={[]} />
    </>
  );

  const header = (
    <div className="app-tab-header px-6 py-3 text-sm text-[var(--muted)]">
      TODO: AppTabHeader — title, refresh, DisplayPrefs scope=&quot;tab&quot;
    </div>
  );

  const handleSort = (key: "label" | "id") => {
    if (sortKey === key) setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    else {
      setSortKey(key);
      setSortDir("asc");
    }
  };

  return (
    <HubDirectoryScreen
      header={header}
      kpis={kpis}
      charts={charts}
      filters={filters}
      query={query}
      onQueryChange={setQuery}
      filterValues={filterValues}
      onFilterValuesChange={setFilterValues}
      filterPlaceholder="Search…"
      filterShortcutScope="default"
      sectionRuleLabel="Items"
      filterRowActions={
        <HubDirectoryBulkActionBar>{/* bulk CTAs — selection: DirectorySearchToolbar.selectionToolbar */}</HubDirectoryBulkActionBar>
      }
    >
      <GoldenDirectoryTable
        rows={filtered}
        sortKey={sortKey}
        sortDir={sortDir}
        onSort={handleSort}
        selectedIds={selectedIds}
        onToggleSelect={toggleSelect}
      />
    </HubDirectoryScreen>
  );
}
